<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Sorting Algorithm Visualizer</title>
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  html, body { height: 100%; }
  body {
    background: #0f1115;
    color: #e6e8ee;
    font-family: "Segoe UI", system-ui, -apple-system, Arial, sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    padding: 24px 16px 40px;
    gap: 18px;
  }
  h1 {
    font-size: 1.4rem;
    font-weight: 600;
    letter-spacing: 0.5px;
    color: #cdd6e4;
  }
  h1 span { color: #4f8cff; }
  .controls {
    display: flex;
    gap: 12px;
    flex-wrap: wrap;
    justify-content: center;
  }
  button {
    background: #1b2130;
    color: #e6e8ee;
    border: 1px solid #2c3547;
    border-radius: 8px;
    padding: 10px 22px;
    font-size: 0.95rem;
    font-weight: 600;
    cursor: pointer;
    transition: background 0.15s ease, border-color 0.15s ease, transform 0.05s ease;
  }
  button:hover { background: #232b3d; border-color: #4f8cff; }
  button:active { transform: translateY(1px); }
  button:disabled { opacity: 0.45; cursor: not-allowed; }
  #sort { border-color: #4f8cff; }
  #status {
    font-size: 0.85rem;
    color: #8a94a6;
    min-height: 1.2em;
  }
  #bars {
    display: flex;
    align-items: flex-end;
    gap: 2px;
    width: min(960px, 96vw);
    height: min(62vh, 520px);
    background: #151a24;
    border: 1px solid #262e3f;
    border-radius: 10px;
    padding: 10px;
    overflow: hidden;
  }
  .bar {
    flex: 1 1 0;
    min-width: 2px;
    background: linear-gradient(180deg, #6ea3ff 0%, #3b6fd4 100%);
    border-radius: 3px 3px 0 0;
    transition: height 0.06s linear, background 0.1s linear;
  }
  .bar.compare { background: linear-gradient(180deg, #ffc46b 0%, #e08c1a 100%); }
  .bar.swap    { background: linear-gradient(180deg, #ff7b7b 0%, #d43b3b 100%); }
  .bar.done    { background: linear-gradient(180deg, #5ee0a8 0%, #2aa876 100%); }
</style>
</head>
<body>

  <h1>Sorting <span>Visualizer</span></h1>

  <div class="controls">
    <button id="sort">Sort</button>
    <button id="shuffle">Shuffle</button>
    <button id="reset">Reset</button>
  </div>

  <div id="status"></div>

  <div id="bars"></div>

<script>
(function () {
  "use strict";

  var barsEl = document.getElementById("bars");
  var statusEl = document.getElementById("status");
  var sortBtn = document.getElementById("sort");
  var shuffleBtn = document.getElementById("shuffle");
  var resetBtn = document.getElementById("reset");

  var DEFAULT_SIZE = 60;
  var arr = [];
  var initial = [];

  // Bubble-sort step state (one comparison per sortStep call).
  var passI = 0;   // current pass
  var passJ = 0;   // current index within pass
  var lastCompare = null; // [j, j+1] of most recent comparison
  var lastSwap = false;

  var animTimer = null;

  function resetSortState() {
    passI = 0;
    passJ = 0;
    lastCompare = null;
    lastSwap = false;
  }

  function isSorted() {
    for (var k = 0; k < arr.length - 1; k++) {
      if (arr[k] > arr[k + 1]) return false;
    }
    return true;
  }

  function render(hlCompare, hlSwap, allDone) {
    barsEl.innerHTML = "";
    var max = 1;
    for (var k = 0; k < arr.length; k++) if (arr[k] > max) max = arr[k];
    var frag = document.createDocumentFragment();
    for (var i = 0; i < arr.length; i++) {
      var d = document.createElement("div");
      d.className = "bar";
      d.style.height = Math.max(2, (arr[i] / max) * 100) + "%";
      if (allDone) {
        d.classList.add("done");
      } else if (hlCompare && (i === hlCompare[0] || i === hlCompare[1])) {
        d.classList.add(hlSwap ? "swap" : "compare");
      }
      frag.appendChild(d);
    }
    barsEl.appendChild(frag);
  }

  function setStatus(msg) { statusEl.textContent = msg || ""; }

  // One single comparison/step of bubble sort.
  // Returns true once the array is fully sorted, false otherwise.
  function sortStep() {
    lastCompare = null;
    lastSwap = false;
    var n = arr.length;
    if (n <= 1) return true;
    if (isSorted()) return true;

    // If state was exhausted (safety), restart the scan.
    if (passI >= n - 1) { passI = 0; passJ = 0; }

    var j = passJ;
    lastCompare = [j, j + 1];
    if (arr[j] > arr[j + 1]) {
      var t = arr[j];
      arr[j] = arr[j + 1];
      arr[j + 1] = t;
      lastSwap = true;
    }
    passJ++;
    if (passJ >= n - 1 - passI) {
      passJ = 0;
      passI++;
    }
    return isSorted();
  }

  function setArray(a) {
    stopAnimation();
    arr = Array.prototype.slice.call(a);
    initial = Array.prototype.slice.call(arr);
    resetSortState();
    render(false, false, isSorted() && arr.length > 0);
    setStatus("");
  }

  function randomArray(size) {
    var a = [];
    for (var i = 0; i < size; i++) {
      a.push(Math.floor(Math.random() * 96) + 5); // values 5..100
    }
    return a;
  }

  function stopAnimation() {
    if (animTimer !== null) {
      cancelAnimationFrame(animTimer);
      animTimer = null;
    }
    sortBtn.disabled = false;
    shuffleBtn.disabled = false;
  }

  function animate() {
    if (animTimer !== null) return; // already running
    if (isSorted()) { render(false, false, true); setStatus("Already sorted."); return; }
    sortBtn.disabled = true;
    shuffleBtn.disabled = true;
    setStatus("Sorting…");

    var stepsPerFrame = Math.max(1, Math.round(arr.length / 30));

    function frame() {
      var done = false;
      for (var s = 0; s < stepsPerFrame; s++) {
        if (sortStep()) { done = true; break; }
      }
      if (done) {
        animTimer = null;
        render(false, false, true);
        setStatus("Sorted!");
        sortBtn.disabled = false;
        shuffleBtn.disabled = false;
        return;
      }
      render(lastCompare, lastSwap, false);
      animTimer = requestAnimationFrame(frame);
    }
    animTimer = requestAnimationFrame(frame);
  }

  sortBtn.addEventListener("click", animate);

  shuffleBtn.addEventListener("click", function () {
    stopAnimation();
    var a = randomArray(DEFAULT_SIZE);
    // Fisher–Yates shuffle of random values (values already random; shuffle for good measure)
    for (var i = a.length - 1; i > 0; i--) {
      var r = Math.floor(Math.random() * (i + 1));
      var t = a[i]; a[i] = a[r]; a[r] = t;
    }
    setArray(a);
    setStatus("Shuffled.");
  });

  resetBtn.addEventListener("click", function () {
    stopAnimation();
    arr = Array.prototype.slice.call(initial);
    resetSortState();
    render(false, false, isSorted() && arr.length > 0);
    setStatus("Reset.");
  });

  // ---- Required programmatic API ----
  window.viz = {
    array: function () { return Array.prototype.slice.call(arr); },
    setArray: function (a) { setArray(a); },
    sortStep: function () { return sortStep(); },
    sorted: function () { return isSorted(); }
  };

  // Initial array on load.
  setArray(randomArray(DEFAULT_SIZE));
})();
</script>
</body>
</html>
